function _demoId() {
  return 'demo_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
}

function _buildDemoGames() {
  const S = _DEMO_RAW.s;
  const games = [];
  const allBowls = [];

  for (let gi = 0; gi < _DEMO_RAW.g.length; gi++) {
    const raw = _DEMO_RAW.g[gi];
    const [tournament, date, format, opposition, players, totalEnds, endScores, rawBowls] = raw;

    const gameId = _demoId();
    const isPairs = format.includes('Pairs');

    const game = {
      id: gameId,
      gameId: gameId,
      tournamentName: tournament,
      format: isPairs ? 'pairs4' : 'singles',
      gameType: 'game',
      matchStructure: 'traditional',
      totalEnds: totalEnds,
      endCount: totalEnds,
      currentEnd: totalEnds,
      completed: true,
      date: date + 'T10:00:00.000Z',
      yourPlayers: players,
      players: players,
      opponentPlayers: [opposition],
      awayPlayers: [],
      bowlsPerPlayer: 4,
      playersPerTeam: isPairs ? players.length : 1,
      numberOfSets: null,
      endsPerSet: null,
      tieBreakEnds: null,
      currentSet: 1,
      setScores: [],
      endNotes: {},
      gameNotes: '',
      jackPosition: { x: 250, y: 250 },
      bowls: [],
      currentPlayerIndex: 0,
      currentTeam: 'yours',
      currentHand: 'forehand',
      matLength: 'short',
      jackLength: 'medium',
      gameNumber: gi + 1,
      [DEMO_DATA_MARKER]: true
    };

    games.push(game);

    for (let bi = 0; bi < rawBowls.length; bi++) {
      const rb = rawBowls[bi];
      const playerName = S[rb[0]];
      const endNum = rb[1];
      const bowlNum = rb[2];
      const hand = rb[3] >= 0 ? S[rb[3]] : 'Forehand';
      const shotType = rb[4] >= 0 ? S[rb[4]] : null;
      const resultCat = rb[5] >= 0 ? S[rb[5]] : null;
      const score = rb[6] >= 0 ? rb[6] : null;
      const jackLen = rb[7] >= 0 ? S[rb[7]] : null;
      const matLen = rb[8] >= 0 ? S[rb[8]] : null;

      let position = 'Player';
      if (isPairs) {
        const pIdx = players.indexOf(playerName);
        if (pIdx === 0) position = 'Lead';
        else if (pIdx > 0) position = 'Skip';
      }

      allBowls.push({
        id: _demoId(),
        gameId: gameId,
        endNumber: endNum,
        end: endNum,
        bowlNumber: bowlNum,
        player: playerName,
        playerName: playerName,
        playerId: playerName,
        team: 'yours',
        hand: hand,
        position: position,
        x: 200 + Math.floor(Math.random() * 100),
        y: 200 + Math.floor(Math.random() * 100),
        scoreValue: score,
        score: score,
        resultCategory: resultCat || '',
        direction: resultCat || '',
        distanceInFeet: score !== null ? (score >= 4 ? 0.3 : score >= 3 ? 0.8 : score >= 2 ? 1.5 : score >= 1 ? 2.5 : 4.0) : 2.0,
        distance: score !== null ? (score >= 4 ? 0.3 : score >= 3 ? 0.8 : score >= 2 ? 1.5 : score >= 1 ? 2.5 : 4.0) : 2.0,
        matLength: matLen || 'Medium',
        jackLength: jackLen || 'Medium',
        shotType: shotType || '',
        quality: score !== null ? (score >= 3 ? 'good' : (score >= 2 ? 'average' : 'poor')) : 'average',
        isDead: false,
        notes: '',
        timestamp: new Date(date + 'T10:00:00.000Z').toISOString(),
        [DEMO_DATA_MARKER]: true
      });
    }
  }

  return { games, bowls: allBowls };
}

// ===== PUBLIC API =====

async function generateDemoData() {
  console.log('[Demo] Loading real tournament data...');

  const { games, bowls } = _buildDemoGames();
  const loadedGameIds = [];

  for (const game of games) {
    await saveGame(game);
    loadedGameIds.push(game.id);
  }

  const bowlsByGame = {};
  for (const b of bowls) {
    if (!bowlsByGame[b.gameId]) bowlsByGame[b.gameId] = [];
    bowlsByGame[b.gameId].push(b);
  }
  for (const gameId of Object.keys(bowlsByGame)) {
    await saveBowlsBatch(bowlsByGame[gameId]);
  }

  await saveSetting('demoGameIds', loadedGameIds);
  await saveSetting('demoDataLoaded', true);

  console.log(`[Demo] Loaded ${games.length} games and ${bowls.length} bowls from real tournament data`);

  return {
    name: 'Real Tournament Data',
    gamesLoaded: games.length,
    deliveriesLoaded: bowls.length
  };
}

async function isDemoDataLoaded() {
  const loaded = await getSetting('demoDataLoaded');
  return loaded === true;
}

async function removeDemoData() {
  const gameIds = await getSetting('demoGameIds');
  if (!gameIds || gameIds.length === 0) {
    const allGames = await getAllGames();
    for (const game of allGames) {
      if (game[DEMO_DATA_MARKER]) {
        await deleteGame(game.id);
      }
    }
  } else {
    for (const id of gameIds) {
      await deleteGame(id);
    }
  }

  await saveSetting('demoGameIds', null);
  await saveSetting('demoDataLoaded', false);
  console.log('[Demo] Demo data removed');
}
